pub struct FrameBuilder<'a: 'b, 'b, A: ::flatbuffers::Allocator + 'a> {
  fbb_: &'b mut ::flatbuffers::FlatBufferBuilder<'a, A>,
  start_: ::flatbuffers::WIPOffset<::flatbuffers::TableUnfinishedWIPOffset>,
}
impl<'a: 'b, 'b, A: ::flatbuffers::Allocator + 'a> FrameBuilder<'a, 'b, A> {
  #[inline]
  pub fn add_fence(&mut self, fence: ::flatbuffers::WIPOffset<Fence<'b >>) {
    self.fbb_.push_slot_always::<::flatbuffers::WIPOffset<Fence>>(Frame::VT_FENCE, fence);
  }
  #[inline]
  pub fn add_body_type(&mut self, body_type: Body) {
    self.fbb_.push_slot::<Body>(Frame::VT_BODY_TYPE, body_type, Body::NONE);
  }
  #[inline]
  pub fn add_body(&mut self, body: ::flatbuffers::WIPOffset<::flatbuffers::UnionWIPOffset>) {
    self.fbb_.push_slot_always::<::flatbuffers::WIPOffset<_>>(Frame::VT_BODY, body);
  }
  #[inline]
  pub fn new(_fbb: &'b mut ::flatbuffers::FlatBufferBuilder<'a, A>) -> FrameBuilder<'a, 'b, A> {
    let start = _fbb.start_table();
    FrameBuilder {
      fbb_: _fbb,
      start_: start,
    }
  }
  #[inline]
  pub fn finish(self) -> ::flatbuffers::WIPOffset<Frame<'a>> {
    let o = self.fbb_.end_table(self.start_);
    self.fbb_.required(o, Frame::VT_FENCE,"fence");
    self.fbb_.required(o, Frame::VT_BODY,"body");
    ::flatbuffers::WIPOffset::new(o.value())
  }
}

